        final int orderingSign = interpolator.isForward() ? +1 : -1;
        SortedSet<EventState> occuringEvents = new TreeSet<EventState>(new Comparator<EventState>() {

            /** {@inheritDoc} */
            public int compare(EventState es0, EventState es1) {
